const spanishKeywords = ['la liga', 'real madrid', 'barcelona', 'atlético de madrid', 'atletico de madrid', 'sevilla fc', 'valencia cf', 'villarreal', 'athletic bilbao', 'real sociedad'];

const seen = new Set();
const cleaned = [];

for (const item of items) {
  const title = (item.json.title || '').toString();
  const content = (item.json.contentSnippet || item.json.content || '').toString();
  const combined = (title + ' ' + content).toLowerCase();

  // Excluir cualquier noticia que mencione La Liga / equipos españoles
  if (spanishKeywords.some(k => combined.includes(k))) continue;

  // Evitar duplicados por título
  if (seen.has(title)) continue;
  seen.add(title);

  cleaned.push({
    json: {
      title: title,
      link: item.json.link || item.json.guid || '',
      pubDate: item.json.pubDate || item.json.isoDate || '',
      snippet: content.substring(0, 300),
    }
  });
}

// Ordenar por fecha descendente (más reciente primero)
cleaned.sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate));

// Quedarnos con las 12 noticias más recientes
return cleaned.slice(0, 12);

const noticias = items.map((item, i) => {
  return `${i + 1}. ${item.json.title}\n   Fecha: ${item.json.pubDate}\n   Resumen: ${item.json.snippet}\n   Fuente: ${item.json.link}`;
}).join('\n\n');

const prompt = `Eres un periodista deportivo especializado en fútbol europeo. A continuación tienes una lista de titulares y resúmenes recientes de la Premier League, Serie A, Bundesliga y Ligue 1 (se excluye deliberadamente La Liga española).

Redacta una crónica en español de entre 300 y 400 palabras que:
- Agrupe las noticias más relevantes por liga cuando tenga sentido.
- Tenga un tono periodístico, ágil y profesional (no una simple lista).
- Destaque 3-4 noticias como las más importantes del día.
- Termine con una frase breve a modo de titular resumen.

Noticias disponibles:

${noticias}`;

return [{ json: { prompt, num_noticias: items.length } }];

const response = items[0].json;
const text = response.content && response.content[0] && response.content[0].text
  ? response.content[0].text
  : JSON.stringify(response);

return [{
  json: {
    cronica: text,
    fecha: new Date().toISOString().slice(0, 10),
  }
}];
